import{_ as a,o as d,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"算电协同——数据中心与新能源融合的新商业模式","description":"","frontmatter":{"updated":"2026-06-23T00:00:00.000Z","visibility":"public"},"headers":[],"relativePath":"算电协同/_深化_2026-06-16_算电协同模式与投资收益.md","filePath":"算电协同/_深化_2026-06-16_算电协同模式与投资收益.md","lastUpdated":1782226922000}'),l={name:"算电协同/_深化_2026-06-16_算电协同模式与投资收益.md"};function i(n,t,s,o,h,b){return d(),r("div",null,[...t[0]||(t[0]=[e(`<h1 id="算电协同——数据中心与新能源融合的新商业模式" tabindex="-1">算电协同——数据中心与新能源融合的新商业模式 <a class="header-anchor" href="#算电协同——数据中心与新能源融合的新商业模式" aria-label="Permalink to &quot;算电协同——数据中心与新能源融合的新商业模式&quot;">​</a></h1><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>算电协同是 2026 年新兴的投资主题。国家六部门 2025.12 发布《关于促进企业数据资源开发利用的意见》，发改委等部门 2026.3 发布《关于促进可再生能源绿色电力证书市场高质量发展的意见》，为算电协同奠定政策基础。核心逻辑：数据中心作为柔性负载，与新能源电站共建，实现绿电直供+余电上网+算力调度三位一体。典型项目 IRR 预计 12%-18%，中西部（内蒙/宁夏/甘肃）度电成本 0.20-0.30 元/kWh，竞争优势显著。</p><h2 id="政策基础" tabindex="-1">政策基础 <a class="header-anchor" href="#政策基础" aria-label="Permalink to &quot;政策基础&quot;">​</a></h2><table tabindex="0"><thead><tr><th>政策</th><th>发布单位</th><th>要点</th></tr></thead><tbody><tr><td>数据产业顶层规划 (2026)</td><td>六部门</td><td>鼓励数据产业与能源产业协同发展</td></tr><tr><td>绿证市场高质量发展意见 (2026.3)</td><td>发改委等部门</td><td>完善绿证制度，降低绿电交易门槛</td></tr><tr><td>数据中心绿色低碳发展行动方案 (2025)</td><td>发改委</td><td>数据中心可再生能源利用率目标 80%+</td></tr><tr><td>全国一体化大数据中心体系 (2024+)</td><td>发改委</td><td>东数西算，算力西部布局</td></tr></tbody></table><h2 id="商业模式" tabindex="-1">商业模式 <a class="header-anchor" href="#商业模式" aria-label="Permalink to &quot;商业模式&quot;">​</a></h2><h3 id="核心结构" tabindex="-1">核心结构 <a class="header-anchor" href="#核心结构" aria-label="Permalink to &quot;核心结构&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>新能源电站 (风电/光伏)</span></span>
<span class="line"><span>    ↓ 绿电直供</span></span>
<span class="line"><span>数据中心 (柔性负载)</span></span>
<span class="line"><span>    ↓ 余电上网</span></span>
<span class="line"><span>电网/交易市场</span></span></code></pre></div><h3 id="三层价值" tabindex="-1">三层价值 <a class="header-anchor" href="#三层价值" aria-label="Permalink to &quot;三层价值&quot;">​</a></h3><ol><li><strong>绿电直供</strong>：数据中心直接消纳新能源电力，降低电费 + 满足可再生能源利用率要求（80%+）</li><li><strong>余电上网</strong>：多余绿电/绿证上网销售，获取额外收益</li><li><strong>算力调度</strong>：利用数据中心作为柔性负载，实现需求侧响应，参与辅助服务市场</li></ol><h3 id="盈利模式" tabindex="-1">盈利模式 <a class="header-anchor" href="#盈利模式" aria-label="Permalink to &quot;盈利模式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>收益来源</th><th>占比</th><th>说明</th></tr></thead><tbody><tr><td>算力服务</td><td>60%-75%</td><td>主要收入来源</td></tr><tr><td>绿电节约</td><td>15%-25%</td><td>较市电价低 30%-50%</td></tr><tr><td>余电上网</td><td>5%-10%</td><td>多余电力上网销售</td></tr><tr><td>辅助服务</td><td>3%-5%</td><td>需求侧响应等</td></tr></tbody></table><h2 id="经济性分析" tabindex="-1">经济性分析 <a class="header-anchor" href="#经济性分析" aria-label="Permalink to &quot;经济性分析&quot;">​</a></h2><h3 id="中西部数据中心-vs-东部数据中心" tabindex="-1">中西部数据中心 vs 东部数据中心 <a class="header-anchor" href="#中西部数据中心-vs-东部数据中心" aria-label="Permalink to &quot;中西部数据中心 vs 东部数据中心&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>中西部（内蒙/宁夏/甘肃）</th><th>东部（北京/上海/广东）</th></tr></thead><tbody><tr><td>度电成本</td><td>0.20-0.30 元/kWh</td><td>0.50-0.80 元/kWh</td></tr><tr><td>电价优势</td><td>省 50%+</td><td>-</td></tr><tr><td>土地成本</td><td>1/10</td><td>基准</td></tr><tr><td>网络延迟</td><td>10-30ms</td><td>&lt;5ms</td></tr><tr><td>适用场景</td><td>训练/推理/存储</td><td>实时/推理</td></tr></tbody></table><h3 id="典型-irr" tabindex="-1">典型 IRR <a class="header-anchor" href="#典型-irr" aria-label="Permalink to &quot;典型 IRR&quot;">​</a></h3><table tabindex="0"><thead><tr><th>项目类型</th><th>IRR 区间</th><th>说明</th></tr></thead><tbody><tr><td>纯数据中心</td><td>8%-12%</td><td>无绿电配套</td></tr><tr><td>数据中心 + 绿电 (中西部)</td><td>12%-18%</td><td>绿电直供降电费</td></tr><tr><td>数据中心 + 绿电 + 调度 (东部)</td><td>10%-15%</td><td>灵活性收益</td></tr><tr><td>算电协同园区 (中西部)</td><td>15%-20%</td><td>规模化+调度优化</td></tr></tbody></table><h2 id="标杆项目" tabindex="-1">标杆项目 <a class="header-anchor" href="#标杆项目" aria-label="Permalink to &quot;标杆项目&quot;">​</a></h2><ul><li><strong>内蒙古乌兰察布</strong>：阿里/华为数据中心与风电/光伏共建</li><li><strong>宁夏中卫</strong>：西部云基地 + 光伏电站</li><li><strong>甘肃庆阳</strong>：东数西算节点 + 新能源基地</li><li><strong>张家口</strong>：数据中心 + 风电直供（可再生能源利用率已达 67%+）</li></ul><h2 id="投资逻辑" tabindex="-1">投资逻辑 <a class="header-anchor" href="#投资逻辑" aria-label="Permalink to &quot;投资逻辑&quot;">​</a></h2><ol><li><strong>中西部是主战场</strong>：电价优势不可替代，东数西算加速布局</li><li><strong>算力需求爆发</strong>：AI 大模型训练/推理驱动算力需求 CAGR 50%+</li><li><strong>政策强制可再生能源利用率</strong>：80%+ 目标倒逼数据中心配建绿电</li><li><strong>柔性调度价值释放</strong>：数据中心参与辅助服务市场增加收益</li></ol><h2 id="风险提示" tabindex="-1">风险提示 <a class="header-anchor" href="#风险提示" aria-label="Permalink to &quot;风险提示&quot;">​</a></h2><ol><li>网络延迟瓶颈限制实时推理场景</li><li>新能源出力波动性需配套储能</li><li>跨省绿电交易机制仍在完善</li><li>数据中心 PUE 能耗指标监管趋严</li><li>算力芯片供应不确定性</li></ol><hr><p><em>来源：发改委、国家能源局、阿里云、华为云、IDC</em><em>更新：2026-06-16</em></p>`,25)])])}const _=a(l,[["render",i]]);export{p as __pageData,_ as default};
